patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..f20bf340face 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2581,7 +2581,7 @@ bool VectorCombine::foldSelectShuffle(Instruction &I, bool FromReduction) {
 /// Check if instruction depends on ZExt and this ZExt can be moved after the
 /// instruction. Move ZExt if it is profitable. For example:
 ///     logic(zext(x),y) -> zext(logic(x,trunc(y)))
-///     lshr((zext(x),y) -> zext(lshr(x,trunc(y)))
+///     lshr((zext(x),y) -> zext(lshr(x,trunc(y))) [only if y is all-zeros]
 /// Cost model calculations takes into account if zext(x) has other users and
 /// whether it can be propagated through them too.
 bool VectorCombine::shrinkType(llvm::Instruction &I) {
@@ -2592,6 +2592,21 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {
     return false;

   Value *ZExtOperand = I.getOperand(I.getOperand(0) == OtherOperand ? 1 : 0);
+  // Guard: Do not narrow LShr(zext(<N x i1>), Y) if Y is not an all-zeros constant.
+  // Truncating a dynamic shift amount to i1 can introduce poison (e.g., shift amount 1).
+  if (I.getOpcode() == Instruction::LShr) {
+    if (auto *SmallVecTy = dyn_cast<FixedVectorType>(ZExted->getType())) {
+      if (SmallVecTy->getElementType()->isIntegerTy(1)) {
+        if (auto *C = dyn_cast<Constant>(OtherOperand)) {
+          if (!C->isNullValue())
+            return false;
+        } else {
+          return false;
+        }
+      }
+    }
+  }
+

   auto *BigTy = cast<FixedVectorType>(I.getType());
   auto *SmallTy = cast<FixedVectorType>(ZExted->getType());

